class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            nums[queries[i][0]] = queries[i][1];
            int maxCount = 0;
            for (int k = 1; k < nums.length; k++) {
                Set<Integer> prefix = new HashSet<>();
                Set<Integer> suffix = new HashSet<>();
                for (int j = 0; j < k; j++) {
                    if (isPrime(nums[j])) {
                        prefix.add(nums[j]);
                    }
                }
                for (int j = k; j < nums.length; j++) {
                    if (isPrime(nums[j])) {
                        suffix.add(nums[j]);
                    }
                }
                maxCount = Math.max(maxCount, prefix.size() + suffix.size());
            }
            result[i] = maxCount;
        }
        return result;
    }

    private boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        if (num == 2) {
            return true;
        }
        if (num % 2 == 0) {
            return false;
        }
        for (int i = 3; i * i <= num; i += 2) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}
